```class Solution {
public:
    string longestPalindrome(string s) {
        int n = s.length();
        vector<int> dp(n, 0);

        for (int i = 0; i < n; i++) {
            for (int j = i; j <= n - i; j++) {
                dp[j] = max(dp[j], dp[j + 1] + 1);
            }
        }

        int maxLen = 0;
        for (int i = 0; i < n; i++) {
            if (dp[i] > maxLen) {
                maxLen = dp[i];
                int start = i;
            }
        }

        return s.substr(start, maxLen);
    }
};```

